SELECT process_name, cpu_usage
FROM processes
WHERE cpu_usage > (SELECT AVG(cpu_usage) FROM processes);

SELECT process_name
FROM processes
WHERE cpu_usage = (
    SELECT MAX(cpu_usage)
    FROM processes
);

SELECT process_id, COUNT(*)
FROM system_alerts
GROUP BY process_id;

SELECT AVG(disk_io) AS average_disk_io
FROM processes
WHERE (strftime('%s', end_time) - strftime('%s', start_time)) > 900;

SELECT p.process_id, p.process_name, so.recommendation
FROM processes p
JOIN system_optimization so ON p.process_id = so.process_id;
